  ('judicial-57112235-moex-00371', 'judicial-57112235', 'judicial-57112235-moex-112-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '美國學者O’Leary與Duffee（1971）提出犯罪矯正政策四大模式，其中對於社區向度的重視程度 較高，關切的重點並非減少犯罪標籤，反而認為烙印的威脅恰可用來控制犯罪人，且管理員大都 具有警察之工作性格，下列那一種模式最符合前述特徵？', '["鎮壓模式（RestraintModel）", "改善模式（ReformModel）", "矯治模式（RehabilitationModel）", "社會復歸模式（ReintegrationModel）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:51+00:00", "source_pdf_sha1": "b89a272a1fc9", "answer_pdf_sha1": "ab056032555e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
